const sourceUrls = [
  {
    source: 'top-funds-yoy',
    url: 'https://www.uitf.com.ph/test_print_topfunds.php?class_id=4&currency=USD&fday=&fmonth=&fyear=&radio1=yoy&tday=&tmonth=&tyear=',
  },
  { source: 'metrobank-daily-navpu', url: 'https://www.uitf.com.ph/daily_navpu.php?bank_id=1' },
  { source: 'pnb-daily-navpu', url: 'https://www.uitf.com.ph/home/daily_navpu.php?bank_id=2' },
  { source: 'bdo-daily-navpu', url: 'https://www.uitf.com.ph/daily_navpu.php?bank_id=6' },
  { source: 'chinabank-daily-navpu', url: 'https://www.uitf.com.ph/home/daily_navpu.php?bank_id=7' },
  { source: 'landbank-daily-navpu', url: 'https://www.uitf.com.ph/daily_navpu.php?bank_id=9' },
];

return sourceUrls.map((source) => ({ json: source }));

function phtDate() {
  const parts = new Intl.DateTimeFormat('en-US', { timeZone: 'Asia/Manila', year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(new Date());
  const pick = (type) => parts.find((part) => part.type === type).value;
  return pick('year') + '-' + pick('month') + '-' + pick('day');
}
function nodeRows(name) {
  return $items(name).flatMap((item) => {
    if (Array.isArray(item.json)) return item.json;
    if (Array.isArray(item.json.data)) return item.json.data;
    return Object.keys(item.json || {}).length ? [item.json] : [];
  });
}
function decode(value) {
  return String(value || '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&#x27;|&#39;/g, String.fromCharCode(39))
    .replace(/&quot;/g, String.fromCharCode(34))
    .replace(/\u00a0/g, ' ');
}
function strip(value) {
  return decode(value).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
}
function parseNumber(value) {
  const match = strip(value).replace(/,/g, '').match(/-?\d+(?:\.\d+)?/);
  return match ? Number(match[0]) : NaN;
}
function parsePercent(value) {
  return parseNumber(String(value || '').replace('%', ''));
}
function parseHtmlRows(html) {
  const rows = [...html.matchAll(/<tr[\s\S]*?<\/tr>/gi)].map((match) => match[0]);
  const parsed = [];
  for (const row of rows) {
    const cells = [...row.matchAll(/<t[dh][^>]*>([\s\S]*?)<\/t[dh]>/gi)].map((match) => strip(match[1]));
    if (cells.length < 3) continue;

    const first = cells[0] || '';
    const hrefMatch = row.match(/fund[_-]?id=(\d+)/i);
    const fundId = hrefMatch ? Number(hrefMatch[1]) : null;

    if (/^\d+$/.test(first)) {
      const rank = Number(first);
      const bank = cells[1] || '';
      const name = cells[2] || '';
      const returnCell = cells.find((cell, index) => index >= 3 && /%/.test(cell)) || cells[cells.length - 1];
      const return1y = parsePercent(returnCell);
      if (name && Number.isFinite(return1y)) parsed.push({ rank, bank, fund_id: fundId, name, navpu: null, return_1y: return1y });
      continue;
    }

    if (/fund name/i.test(first)) continue;

    const name = first;
    let navpuCell = null;
    let returnCell = null;

    if (cells.length >= 5 && /fund/i.test(cells[1]) && Number.isFinite(parseNumber(cells[2])) && Number.isFinite(parsePercent(cells[3]))) {
      navpuCell = cells[2];
      returnCell = cells[3];
    } else if (cells.length >= 4 && Number.isFinite(parseNumber(cells[1])) && Number.isFinite(parsePercent(cells[2]))) {
      navpuCell = cells[1];
      returnCell = cells[2];
    } else if (cells.length >= 4 && Number.isFinite(parseNumber(cells[2])) && Number.isFinite(parsePercent(cells[3]))) {
      navpuCell = cells[2];
      returnCell = cells[3];
    }

    const navpu = parseNumber(navpuCell);
    const return1y = parsePercent(returnCell);
    if (name && Number.isFinite(return1y)) {
      parsed.push({ rank: null, bank: '', fund_id: fundId, name, navpu: Number.isFinite(navpu) ? navpu : null, return_1y: return1y });
    }
  }
  return parsed;
}
function parseTextRows(text) {
  const parsed = [];
  const lines = String(text || '').split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
  for (let i = 0; i < lines.length; i += 1) {
    const line = lines[i];
    const pipeCells = line.includes('|') ? line.split('|').map((cell) => strip(cell)).filter(Boolean) : [];
    if (pipeCells.length >= 4 && /^\d+$/.test(pipeCells[0]) && /%/.test(pipeCells[pipeCells.length - 1])) {
      const return1y = parsePercent(pipeCells[pipeCells.length - 1]);
      if (Number.isFinite(return1y)) parsed.push({ rank: Number(pipeCells[0]), bank: pipeCells[1], name: pipeCells[2], navpu: null, return_1y: return1y });
      continue;
    }
    if (pipeCells.length >= 4 && !/^\d+$/.test(pipeCells[0])) {
      const hasClassification = /fund/i.test(pipeCells[1] || '');
      const navpu = parseNumber(hasClassification ? pipeCells[2] : pipeCells[1]);
      const return1y = parsePercent(hasClassification ? pipeCells[3] : pipeCells[2]);
      if (pipeCells[0] && Number.isFinite(return1y)) {
        parsed.push({ rank: null, bank: '', name: pipeCells[0], navpu: Number.isFinite(navpu) ? navpu : null, return_1y: return1y });
      }
      continue;
    }
    const compactMatch = line.match(/^\s*(\d+)\s+(.+?)\s{2,}(.+?)\s+(-?\d+(?:\.\d+)?)%\s*$/);
    if (compactMatch) {
      parsed.push({ rank: Number(compactMatch[1]), bank: strip(compactMatch[2]), name: strip(compactMatch[3]), navpu: null, return_1y: Number(compactMatch[4]) });
    }
  }
  return parsed;
}
const funds = nodeRows('Get Target Funds').filter((row) => row.id);
if (!funds.length) throw new Error('No target USD UITF funds returned from Supabase');
const benchmarks = nodeRows('Get Latest Benchmark').filter((row) => row.rate !== undefined && row.rate !== null);
if (!benchmarks.length) throw new Error('Missing US_TBILL_90D benchmark. Run the US T-Bill benchmark workflow first.');
const benchmarkRate = Number(benchmarks[0].rate);
const benchmarkAfterTaxRate = benchmarkRate;
const sourceItems = $items('Fetch UITF Source');
const htmlDocuments = sourceItems.map((item) => {
  const raw = item.json.data || item.json.body || item.json.html || item.json.response || '';
  return typeof raw === 'string' ? raw : JSON.stringify(raw || {});
}).filter((html) => html && html !== '{}');
if (!htmlDocuments.length) throw new Error('UITF sources returned no usable bodies. Fetch item count: ' + sourceItems.length);
let scraped = [];
const sourceSamples = [];
for (const html of htmlDocuments) {
  const text = strip(html).replace(/\s*\|\s*/g, ' | ');
  if (/incapsula|request unsuccessful|incident id/i.test(html)) throw new Error('UITF source blocked the n8n request: ' + text.slice(0, 300));
  const parsed = parseHtmlRows(html);
  scraped = scraped.concat(parsed.length ? parsed : parseTextRows(text));
  if (sourceSamples.length < 3) sourceSamples.push(text.slice(0, 220));
}
if (!scraped.length) throw new Error('No UITF source rows parsed. Samples: ' + sourceSamples.join(' || '));
const allowlist = {
  'bdo dollar money market fund': 'bdo-dollar-money-market-fund',
  'chinabank dollar cash fund': 'chinabank-dollar-cash-fund',
  'landbank us dollar money market fund': 'landbank-us-dollar-money-market-fund',
  'landbank us money market fund': 'landbank-us-dollar-money-market-fund',
  'metro dollar money market fund': 'metro-dollar-money-market-fund',
  'pnb prime dollar money market fund': 'pnb-prime-dollar-money-market-fund'
};
const norm = (value) => String(value || '').toLowerCase().replace(/&/g, 'and').split('$').join(' dollar ').replace(/[^a-z0-9]+/g, ' ').trim();
const byId = new Map(scraped.filter((row) => row.fund_id).map((row) => [String(row.fund_id), row]));
const bySlug = new Map();
for (const row of scraped) {
  const normalizedName = norm(row.name);
  const direct = allowlist[normalizedName];
  if (direct) bySlug.set(direct, row);
  for (const [key, slug] of Object.entries(allowlist)) {
    if (!bySlug.has(slug) && normalizedName.includes(key)) bySlug.set(slug, row);
  }
}
const today = phtDate();
const output = [];
const missing = [];
for (const fund of funds) {
  const scrapedRow = (fund.uitf_fund_id ? byId.get(String(fund.uitf_fund_id)) : null) || bySlug.get(fund.slug);
  if (!scrapedRow) {
    missing.push(fund.provider + ' - ' + fund.name);
    continue;
  }
  const grossYield = Number(scrapedRow.return_1y) / 100;
  const trustFee = Number(fund.trust_fee_pct || 0);
  const afterTaxYield = grossYield * 0.8;
  const netYield = afterTaxYield - trustFee;
  output.push({ json: { fund_id: fund.id, date: today, navpu: scrapedRow.navpu, gross_yield_1y: Number(grossYield.toFixed(6)), after_tax_yield: Number(afterTaxYield.toFixed(6)), net_yield: Number(netYield.toFixed(6)), benchmark_rate: benchmarkRate, vs_benchmark: Number((netYield - benchmarkAfterTaxRate).toFixed(6)), data_source: 'scraper' } });
}
if (missing.length) {
  const seen = scraped.slice(0, 40).map((row) => row.name + ' (' + row.return_1y + '%)').join('; ');
  throw new Error('Missing scraped rows for ' + missing.length + ' target funds: ' + missing.join('; ') + '. Parsed rows sample: ' + seen);
}
return output;
